import javafx.application.Application;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.Scene;
import javafx.scene.control.*;
import javafx.scene.layout.VBox;
import javafx.stage.Stage;

import java.util.Optional;

public class DialogsExample extends Application {
    @Override
    public void start(Stage primaryStage) {
        VBox root = new VBox(15);
        root.setPadding(new Insets(20));
        root.setAlignment(Pos.CENTER);

        Label resultLabel = new Label("Results will appear here");
        resultLabel.setStyle("-fx-font-size: 14px;");

        // 1. Alert - Information
        Button infoBtn = new Button("Information Alert");
        infoBtn.setOnAction(e -> {
            Alert alert = new Alert(Alert.AlertType.INFORMATION);
            alert.setTitle("Information");
            alert.setHeaderText("Information Dialog");
            alert.setContentText("This is an information message!");
            alert.showAndWait();
            resultLabel.setText("Information dialog shown");
        });

        // 2. Alert - Warning
        Button warningBtn = new Button("Warning Alert");
        warningBtn.setOnAction(e -> {
            Alert alert = new Alert(Alert.AlertType.WARNING);
            alert.setTitle("Warning");
            alert.setHeaderText("Warning Dialog");
            alert.setContentText("This is a warning message!");
            alert.showAndWait();
            resultLabel.setText("Warning dialog shown");
        });

        // 3. Alert - Error
        Button errorBtn = new Button("Error Alert");
        errorBtn.setOnAction(e -> {
            Alert alert = new Alert(Alert.AlertType.ERROR);
            alert.setTitle("Error");
            alert.setHeaderText("Error Dialog");
            alert.setContentText("This is an error message!");
            alert.showAndWait();
            resultLabel.setText("Error dialog shown");
        });

        // 4. Alert - Confirmation
        Button confirmBtn = new Button("Confirmation Dialog");
        confirmBtn.setOnAction(e -> {
            Alert alert = new Alert(Alert.AlertType.CONFIRMATION);
            alert.setTitle("Confirmation");
            alert.setHeaderText("Confirmation Dialog");
            alert.setContentText("Are you sure you want to proceed?");

            Optional<ButtonType> result = alert.showAndWait();
            if (result.isPresent() && result.get() == ButtonType.OK) {
                resultLabel.setText("User clicked OK");
            } else {
                resultLabel.setText("User clicked Cancel or closed");
            }
        });

        // 5. Custom dialog
        Button customBtn = new Button("Custom Dialog");
        customBtn.setOnAction(e -> {
            // Create custom dialog
            Dialog<String> dialog = new Dialog<>();
            dialog.setTitle("Custom Dialog");
            dialog.setHeaderText("Enter your information");

            // Set the button types
            ButtonType okButton = new ButtonType("OK", ButtonBar.ButtonData.OK_DONE);
            dialog.getDialogPane().getButtonTypes().addAll(okButton, ButtonType.CANCEL);

            // Create the content
            VBox content = new VBox(10);
            content.setPadding(new Insets(20));

            TextField nameField = new TextField();
            nameField.setPromptText("Enter name");

            TextField emailField = new TextField();
            emailField.setPromptText("Enter email");

            content.getChildren().addAll(
                new Label("Name:"),
                nameField,
                new Label("Email:"),
                emailField
            );

            dialog.getDialogPane().setContent(content);

            // Convert the result
            dialog.setResultConverter(dialogButton -> {
                if (dialogButton == okButton) {
                    return "Name: " + nameField.getText() + ", Email: " + emailField.getText();
                }
                return null;
            });

            Optional<String> result = dialog.showAndWait();
            result.ifPresent(data -> resultLabel.setText("Result: " + data));
        });

        // 6. TextInputDialog
        Button inputBtn = new Button("Text Input Dialog");
        inputBtn.setOnAction(e -> {
            TextInputDialog dialog = new TextInputDialog("Default value");
            dialog.setTitle("Text Input");
            dialog.setHeaderText("Enter your name");
            dialog.setContentText("Name:");

            Optional<String> result = dialog.showAndWait();
            result.ifPresent(name -> resultLabel.setText("Hello, " + name + "!"));
        });

        // 7. ChoiceDialog
        Button choiceBtn = new Button("Choice Dialog");
        choiceBtn.setOnAction(e -> {
            ChoiceDialog<String> dialog = new ChoiceDialog<>("Option 2", "Option 1", "Option 2", "Option 3", "Option 4");
            dialog.setTitle("Choice Dialog");
            dialog.setHeaderText("Choose an option");
            dialog.setContentText("Select:");

            Optional<String> result = dialog.showAndWait();
            result.ifPresent(choice -> resultLabel.setText("You chose: " + choice));
        });

        // 8. Alert with custom buttons
        Button customAlertBtn = new Button("Custom Buttons Alert");
        customAlertBtn.setOnAction(e -> {
            Alert alert = new Alert(Alert.AlertType.CONFIRMATION);
            alert.setTitle("Custom Buttons");
            alert.setHeaderText("Choose an action");
            alert.setContentText("What would you like to do?");

            ButtonType saveBtn = new ButtonType("Save");
            ButtonType discardBtn = new ButtonType("Discard");
            ButtonType cancelBtn = new ButtonType("Cancel", ButtonBar.ButtonData.CANCEL_CLOSE);

            alert.getButtonTypes().setAll(saveBtn, discardBtn, cancelBtn);

            Optional<ButtonType> result = alert.showAndWait();
            if (result.isPresent()) {
                if (result.get() == saveBtn) {
                    resultLabel.setText("User chose Save");
                } else if (result.get() == discardBtn) {
                    resultLabel.setText("User chose Discard");
                } else {
                    resultLabel.setText("User chose Cancel");
                }
            }
        });

        root.getChildren().addAll(
            new Label("--- Dialogs & Alerts ---"),
            infoBtn,
            warningBtn,
            errorBtn,
            confirmBtn,
            customBtn,
            inputBtn,
            choiceBtn,
            customAlertBtn,
            new Separator(),
            resultLabel
        );

        Scene scene = new Scene(root, 500, 650);

        primaryStage.setTitle("Dialogs & Alerts");
        primaryStage.setScene(scene);
        primaryStage.show();
    }

    public static void main(String[] args) {
        launch(args);
    }
}

