import javafx.application.Application;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.Scene;
import javafx.scene.control.*;
import javafx.scene.layout.VBox;
import javafx.stage.Stage;

import java.util.Optional;

public class DialogPractice extends Application {
    @Override
    public void start(Stage primaryStage) {
        VBox root = new VBox(15);
        root.setPadding(new Insets(20));
        root.setAlignment(Pos.CENTER);

        Label resultLabel = new Label("Ready");

        Button deleteBtn = new Button("Delete File");
        deleteBtn.setOnAction(e -> {
            Alert alert = new Alert(Alert.AlertType.CONFIRMATION);
            alert.setTitle("Delete File");
            alert.setHeaderText("Confirm Deletion");
            alert.setContentText("Are you sure you want to delete this file?");

            Optional<ButtonType> result = alert.showAndWait();
            if (result.isPresent() && result.get() == ButtonType.OK) {
                resultLabel.setText("File deleted!");
            } else {
                resultLabel.setText("Deletion cancelled");
            }
        });

        root.getChildren().addAll(deleteBtn, resultLabel);

        Scene scene = new Scene(root, 400, 200);
        primaryStage.setTitle("Dialog Practice");
        primaryStage.setScene(scene);
        primaryStage.show();
    }

    public static void main(String[] args) {
        launch(args);
    }
}
